import React, { useState, useEffect } from 'react';
import { Search, Filter, ShoppingBag } from 'lucide-react';

const Home = ({ isLoggedIn, userRole }) => {
  const [todasLasOfertas, setTodasLasOfertas] = useState([]);
  const [ofertasFiltradas, setOfertasFiltradas] = useState([]);
  const [busqueda, setBusqueda] = useState('');
  const [zona, setZona] = useState('Todas las zonas');

  const zonasTucuman = ['Todas las zonas', 'Barrio Norte', 'Barrio Sur', 'Yerba Buena', 'Tafí Viejo'];

  useEffect(() => {
    const locales = JSON.parse(localStorage.getItem('mis-locales') || "[]");
    let acumulador = [];
    locales.forEach(local => {
      const ofertasLocal = JSON.parse(localStorage.getItem(`ofertas-local-${local.id}`) || "[]");
      acumulador = [...acumulador, ...ofertasLocal.map(o => ({
        ...o,
        nombreLocal: local.nombre,
        zona: local.zona || 'Centro'
      }))];
    });
    setTodasLasOfertas(acumulador);
  }, []);

  useEffect(() => {
    let resultado = todasLasOfertas.filter(o => {
      const coincideBusqueda = o.producto.toLowerCase().includes(busqueda.toLowerCase());
      const coincideZona = zona === 'Todas las zonas' || o.zona === zona;
      return coincideBusqueda && coincideZona;
    });
    setOfertasFiltradas(resultado);
  }, [busqueda, zona, todasLasOfertas]);

  return (
    <div style={{ background: '#ffffff', minHeight: '100vh' }}>
      
      {/* --- SECCIÓN HERO (Tu imagen y texto original) --- */}
      <div style={heroWrapper}>
        <div style={heroOverlay}>
          <div style={heroTextContainer}>
            <h1 style={heroTitle}>
              Encontrá todo lo que buscás <br/> 
              <span style={{color: '#e67e22'}}>al mejor precio</span>
            </h1>
            <p style={heroSubtitle}>
              Explorá ofertas increíbles en tecnología, moda, hogar y mucho más cerca de vos.
            </p>

            {/* BUSCADOR ESTILO PREMIUM (Solo para clientes/visitantes) */}
            {userRole !== 'vendedor' && (
              <div style={searchGlass}>
                <Search size={22} color="#64748b" />
                <input 
                  type="text" 
                  placeholder="Buscá productos, marcas y más..." 
                  style={inputGlass}
                  onChange={(e) => setBusqueda(e.target.value)}
                />
                <button style={btnSearchHero}>Buscar</button>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* --- BARRA DE FILTROS --- */}
      <div style={filterContainer}>
        <div style={filterLabel}>
          <Filter size={18} /> <span>Filtrar por zona:</span>
        </div>
        <div style={zonaList}>
          {zonasTucuman.map(z => (
            <button 
              key={z} 
              onClick={() => setZona(z)} 
              style={zona === z ? zonaActive : zonaInactive}
            >
              {z}
            </button>
          ))}
        </div>
      </div>

      {/* --- GRILLA DE OFERTAS --- */}
      <div style={contentWrapper}>
        <h2 style={sectionHeader}>Ofertas destacadas del día</h2>
        
        {ofertasFiltradas.length > 0 ? (
          <div style={productGrid}>
            {ofertasFiltradas.map(o => (
              <div key={o.id} style={productCard}>
                <div style={imageContainer}>
                  {o.imagen ? (
                    <img src={o.imagen} alt={o.producto} style={imgMain} />
                  ) : (
                    <ShoppingBag size={48} color="#e2e8f0" />
                  )}
                  <div style={discountBadge}>Oferta</div>
                </div>
                <div style={cardBody}>
                  <span style={shopName}>{o.nombreLocal}</span>
                  <h3 style={productName}>{o.producto}</h3>
                  <div style={priceContainer}>
                    <span style={currentPrice}>${o.precioNuevo}</span>
                  </div>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div style={emptyState}>
            <p>No se encontraron productos en esta zona. <br/> ¡Explorá otras áreas o buscá un término diferente!</p>
          </div>
        )}
      </div>
    </div>
  );
};

/* --- ESTILOS PARA RECUPERAR LA BELLEZA --- */
const heroWrapper = {
  height: '550px',
  backgroundImage: 'url("https://images.unsplash.com/photo-1441986300917-64674bd600d8?q=80&w=2070&auto=format&fit=crop")', // Imagen de shopping general
  backgroundSize: 'cover',
  backgroundPosition: 'center',
  position: 'relative'
};

const heroOverlay = {
  position: 'absolute', top: 0, left: 0, right: 0, bottom: 0,
  background: 'linear-gradient(to right, rgba(30, 41, 59, 0.8), rgba(30, 41, 59, 0.4))',
  display: 'flex', alignItems: 'center', padding: '0 8%'
};

const heroTextContainer = { maxWidth: '700px' };
const heroTitle = { color: 'white', fontSize: '3.8rem', fontWeight: '900', marginBottom: '20px', lineHeight: '1.1' };
const heroSubtitle = { color: '#cbd5e1', fontSize: '1.4rem', marginBottom: '40px', fontWeight: '400' };

const searchGlass = {
  display: 'flex', background: 'white', padding: '8px', borderRadius: '15px',
  boxShadow: '0 20px 40px rgba(0,0,0,0.3)', alignItems: 'center', paddingLeft: '20px'
};

const inputGlass = { flex: 1, border: 'none', outline: 'none', fontSize: '1.1rem', padding: '15px' };
const btnSearchHero = { background: '#e67e22', color: 'white', border: 'none', padding: '15px 35px', borderRadius: '12px', fontWeight: 'bold', cursor: 'pointer', fontSize: '1rem' };

const filterContainer = { padding: '30px 8%', display: 'flex', alignItems: 'center', gap: '20px', borderBottom: '1px solid #f1f5f9', flexWrap: 'wrap' };
const filterLabel = { display: 'flex', alignItems: 'center', gap: '8px', fontWeight: 'bold', color: '#64748b' };
const zonaList = { display: 'flex', gap: '10px' };
const zonaInactive = { padding: '8px 18px', borderRadius: '10px', border: '1px solid #e2e8f0', background: 'white', cursor: 'pointer', color: '#64748b', fontWeight: '500' };
const zonaActive = { ...zonaInactive, background: '#1e293b', color: 'white', borderColor: '#1e293b' };

const contentWrapper = { padding: '50px 8%' };
const sectionHeader = { fontSize: '2rem', color: '#1e293b', marginBottom: '40px', fontWeight: '800' };
const productGrid = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: '35px' };

const productCard = { background: 'white', borderRadius: '25px', overflow: 'hidden', border: '1px solid #f1f5f9', transition: 'transform 0.3s ease', cursor: 'pointer', boxShadow: '0 4px 20px rgba(0,0,0,0.02)' };
const imageContainer = { height: '240px', background: '#f8fafc', display: 'flex', justifyContent: 'center', alignItems: 'center', position: 'relative' };
const imgMain = { width: '100%', height: '100%', objectFit: 'cover' };
const discountBadge = { position: 'absolute', top: '15px', left: '15px', background: '#e67e22', color: 'white', padding: '5px 12px', borderRadius: '8px', fontSize: '0.8rem', fontWeight: 'bold' };

const cardBody = { padding: '20px' };
const shopName = { fontSize: '0.75rem', color: '#e67e22', fontWeight: 'bold', textTransform: 'uppercase', letterSpacing: '1px' };
const productName = { margin: '8px 0', fontSize: '1.2rem', color: '#1e293b', fontWeight: '700' };
const priceContainer = { display: 'flex', alignItems: 'center', marginTop: '15px' };
const currentPrice = { fontSize: '1.6rem', fontWeight: '900', color: '#1e293b' };

const emptyState = { textAlign: 'center', padding: '100px 0', color: '#94a3b8', fontSize: '1.2rem' };

export default Home;
